+#![forbid(unsafe_code)]
+
+use std::error::Error;
+use std::fs;
+use std::path::PathBuf;
+
+use frankenengine_engine::parser_oracle::{
+    OracleGateMode, OraclePartition, ParserOracleConfig, run_parser_oracle,
+};
+
+#[derive(Debug)]
+struct CliArgs {
+    config: ParserOracleConfig,
+    out_path: Option<PathBuf>,
+}
+
+fn main() {
+    match run() {
+        Ok(exit_code) => std::process::exit(exit_code),
+        Err(error) => {
+            eprintln!("{error}");
+            std::process::exit(1);
+        }
+    }
+}
+
+fn run() -> Result<i32, Box<dyn Error>> {
+    let args = parse_args(std::env::args().skip(1))?;
+    let report = run_parser_oracle(&args.config)?;
+    let json = serde_json::to_string_pretty(&report)?;
+
+    if let Some(out_path) = &args.out_path {
+        if let Some(parent) = out_path.parent() {
+            fs::create_dir_all(parent)?;
+        }
+        fs::write(out_path, json.as_bytes())?;
+    }
+
+    println!("{json}");
+
+    if args.config.gate_mode == OracleGateMode::FailClosed && report.decision.promotion_blocked {
+        Ok(2)
+    } else {
+        Ok(0)
+    }
+}
+
+fn parse_args<I>(args: I) -> Result<CliArgs, Box<dyn Error>>
+where
+    I: IntoIterator<Item = String>,
+{
+    let mut partition = OraclePartition::Smoke;
+    let mut gate_mode = OracleGateMode::ReportOnly;
+    let mut seed = 1u64;
+    let mut fixture_catalog =
+        PathBuf::from(frankenengine_engine::parser_oracle::DEFAULT_FIXTURE_CATALOG_PATH);
+    let mut trace_id = None::<String>;
+    let mut decision_id = None::<String>;
+    let mut policy_id = None::<String>;
+    let mut out_path = None::<PathBuf>;
+
+    let mut iter = args.into_iter();
+    while let Some(arg) = iter.next() {
+        match arg.as_str() {
+            "--partition" => {
+                let value = iter
+                    .next()
+                    .ok_or_else(|| "missing value for --partition".to_string())?;
+                partition = value.parse::<OraclePartition>()?;
+            }
+            "--gate-mode" => {
+                let value = iter
+                    .next()
+                    .ok_or_else(|| "missing value for --gate-mode".to_string())?;
+                gate_mode = value.parse::<OracleGateMode>()?;
+            }
+            "--seed" => {
+                let value = iter
+                    .next()
+                    .ok_or_else(|| "missing value for --seed".to_string())?;
+                seed = value.parse::<u64>()?;
+            }
+            "--fixture-catalog" => {
+                let value = iter
+                    .next()
+                    .ok_or_else(|| "missing value for --fixture-catalog".to_string())?;
+                fixture_catalog = PathBuf::from(value);
+            }
+            "--trace-id" => {
+                let value = iter
+                    .next()
+                    .ok_or_else(|| "missing value for --trace-id".to_string())?;
+                trace_id = Some(value);
+            }
+            "--decision-id" => {
+                let value = iter
+                    .next()
+                    .ok_or_else(|| "missing value for --decision-id".to_string())?;
+                decision_id = Some(value);
+            }
+            "--policy-id" => {
+                let value = iter
+                    .next()
+                    .ok_or_else(|| "missing value for --policy-id".to_string())?;
+                policy_id = Some(value);
+            }
+            "--out" => {
+                let value = iter
+                    .next()
+                    .ok_or_else(|| "missing value for --out".to_string())?;
+                out_path = Some(PathBuf::from(value));
+            }
+            "--help" | "-h" => {
+                print_help();
+                return Ok(CliArgs {
+                    config: ParserOracleConfig::with_defaults(partition, gate_mode, seed),
+                    out_path,
+                });
+            }
+            other => {
+                return Err(format!("unknown argument `{other}`").into());
+            }
+        }
+    }
+
+    let mut config = ParserOracleConfig::with_defaults(partition, gate_mode, seed);
+    config.fixture_catalog_path = fixture_catalog;
+    if let Some(value) = trace_id {
+        config.trace_id = value;
+    }
+    if let Some(value) = decision_id {
+        config.decision_id = value;
+    }
+    if let Some(value) = policy_id {
+        config.policy_id = value;
+    }
+
+    Ok(CliArgs { config, out_path })
+}
+
+fn print_help() {
+    println!("franken_parser_oracle_report");
+    println!("  --partition <smoke|full|nightly>");
+    println!("  --gate-mode <report_only|fail_closed>");
+    println!("  --seed <u64>");
+    println!("  --fixture-catalog <path>");
+    println!("  --trace-id <id>");
+    println!("  --decision-id <id>");
+    println!("  --policy-id <id>");
+    println!("  --out <path>");
+}

@@ -0,0 +1,160 @@
+#![forbid(unsafe_code)]
+
+use std::fs;
+use std::path::Path;
+use std::time::Instant;
+
+use chrono::Utc;
+use frankenengine_engine::ast::ParseGoal;
+use frankenengine_engine::parser::{CanonicalEs2020Parser, ParserMode, ParserOptions};
+use serde::{Deserialize, Serialize};
+
+const FIXTURE_PATH: &str =
+    "crates/franken-engine/tests/fixtures/parser_phase0_semantic_fixtures.json";
+const REPETITIONS: usize = 128;
+
+#[derive(Debug, Deserialize)]
+struct FixtureSpec {
+    id: String,
+    goal: String,
+    source: String,
+    expected_hash: String,
+}
+
+#[derive(Debug, Deserialize)]
+struct FixtureCatalog {
+    schema_version: String,
+    parser_mode: String,
+    fixtures: Vec<FixtureSpec>,
+}
+
+#[derive(Debug, Serialize)]
+struct LatencySummary {
+    sample_count: usize,
+    repetitions: usize,
+    p50_ns: u64,
+    p95_ns: u64,
+    p99_ns: u64,
+}
+
+#[derive(Debug, Serialize)]
+struct BaselineReport {
+    schema_version: String,
+    generated_at_utc: String,
+    parser_mode: String,
+    fixture_catalog_path: String,
+    fixture_catalog_schema: String,
+    fixture_count: usize,
+    deterministic_hash_validation: bool,
+    grammar_completeness: frankenengine_engine::parser::GrammarCompletenessSummary,
+    parser_budget: frankenengine_engine::parser::ParserBudget,
+    latency: LatencySummary,
+}
+
+fn parse_goal(raw: &str) -> Result<ParseGoal, String> {
+    match raw {
+        "script" => Ok(ParseGoal::Script),
+        "module" => Ok(ParseGoal::Module),
+        other => Err(format!("unknown fixture goal: {other}")),
+    }
+}
+
+fn quantile(sorted: &[u64], q_percent: usize) -> u64 {
+    if sorted.is_empty() {
+        return 0;
+    }
+    let idx = (sorted.len() - 1).saturating_mul(q_percent) / 100;
+    sorted[idx]
+}
+
+fn run() -> Result<BaselineReport, String> {
+    let bytes = fs::read(Path::new(FIXTURE_PATH))
+        .map_err(|error| format!("failed to read fixture catalog `{FIXTURE_PATH}`: {error}"))?;
+    let catalog: FixtureCatalog = serde_json::from_slice(&bytes)
+        .map_err(|error| format!("failed to parse fixture catalog json: {error}"))?;
+
+    if catalog.parser_mode != ParserMode::ScalarReference.as_str() {
+        return Err(format!(
+            "fixture catalog parser_mode must be `{}`",
+            ParserMode::ScalarReference.as_str()
+        ));
+    }
+
+    let parser = CanonicalEs2020Parser;
+    let options = ParserOptions::default();
+
+    let mut deterministic_hash_validation = true;
+    for fixture in &catalog.fixtures {
+        let tree = parser
+            .parse_with_options(
+                fixture.source.as_str(),
+                parse_goal(fixture.goal.as_str())?,
+                &options,
+            )
+            .map_err(|error| format!("fixture `{}` parse failed: {error}", fixture.id))?;
+
+        if tree.canonical_hash() != fixture.expected_hash {
+            deterministic_hash_validation = false;
+        }
+    }
+
+    let mut samples_ns = Vec::<u64>::new();
+    for _ in 0..REPETITIONS {
+        for fixture in &catalog.fixtures {
+            let start = Instant::now();
+            let _tree = parser
+                .parse_with_options(
+                    fixture.source.as_str(),
+                    parse_goal(fixture.goal.as_str())?,
+                    &options,
+                )
+                .map_err(|error| {
+                    format!(
+                        "fixture `{}` parse failed during timing: {error}",
+                        fixture.id
+                    )
+                })?;
+            let elapsed_ns = u64::try_from(start.elapsed().as_nanos()).unwrap_or(u64::MAX);
+            samples_ns.push(elapsed_ns);
+        }
+    }
+
+    samples_ns.sort_unstable();
+
+    let latency = LatencySummary {
+        sample_count: samples_ns.len(),
+        repetitions: REPETITIONS,
+        p50_ns: quantile(&samples_ns, 50),
+        p95_ns: quantile(&samples_ns, 95),
+        p99_ns: quantile(&samples_ns, 99),
+    };
+
+    let grammar_completeness = parser.scalar_reference_grammar_matrix().summary();
+
+    Ok(BaselineReport {
+        schema_version: "franken-engine.parser-phase0.baseline.v1".to_string(),
+        generated_at_utc: Utc::now().to_rfc3339_opts(chrono::SecondsFormat::Secs, true),
+        parser_mode: ParserMode::ScalarReference.as_str().to_string(),
+        fixture_catalog_path: FIXTURE_PATH.to_string(),
+        fixture_catalog_schema: catalog.schema_version,
+        fixture_count: catalog.fixtures.len(),
+        deterministic_hash_validation,
+        grammar_completeness,
+        parser_budget: options.budget,
+        latency,
+    })
+}
+
+fn main() {
+    match run() {
+        Ok(report) => {
+            let json = serde_json::to_string_pretty(&report)
+                .expect("serialize parser phase0 baseline report");
+            println!("{json}");
+        }
+        Err(error) => {
+            eprintln!("{error}");
+            std::process::exit(1);
+        }
+    }
+}

