+                    self.charge_bytes(string_bytes(binding))?;
+                }
+                ArenaNode::Import {
+                    binding: import.binding.clone(),
+                    source: import.source.clone(),
+                    span,
+                }
+            }
+            Statement::Export(export) => {
+                let span = self.alloc_span(&export.span)?;
+                self.charge_bytes(NODE_BASE_ESTIMATED_BYTES)?;
