+    fn materialize_statement(&self, handle: NodeHandle) -> Result<Statement, ArenaError> {
+        let node = self.node(handle)?.clone();
+        match node {
+            ArenaNode::Import {
+                binding,
+                source,
+                span,
+            } => Ok(Statement::Import(ImportDeclaration {
+                binding,
+                source,
+                span: self.span(span)?.clone(),
+            })),
