+                Ok(Statement::Export(ExportDeclaration {
+                    kind: ExportKind::Default(self.materialize_expression(expression)?),
+                    span: self.span(span)?.clone(),
+                }))
+            }
+            ArenaNode::ExportNamedClause { clause, span } => {
+                Ok(Statement::Export(ExportDeclaration {
+                    kind: ExportKind::NamedClause(clause),
+                    span: self.span(span)?.clone(),
+                }))
+            }
