+                            &mut checks,
+                            "signature_valid",
+                            "attestation payload signature verified".to_string(),
+                        ),
+                        Err(error) => fail_check(
+                            &mut checks,
+                            "signature_valid",
+                            CODE_ATTESTATION_SIGNATURE,
+                            format!("signature verification failed: {error}"),
+                        ),
+                    }
+                }
