+        }
+        _ => fail_check(
+            &mut checks,
+            "signature_presence_consistent",
+            CODE_ATTESTATION_ENVELOPE,
+            "signer_verification_key_hex and signature_hex must both be set or both be empty"
+                .to_string(),
+        ),
+    }
